56:  * // check {@link #define(String, Type, Object, Importance, String)} for more details.
57:  * defs.define(&quot;config_with_default&quot;, Type.STRING, &quot;default string value&quot;, Importance.High, &quot;Configuration with default value.&quot;);
58:  * // check {@link #define(String, Type, Object, Validator, Importance, String)} for more details.
59:  * defs.define(&quot;config_with_validator&quot;, Type.INT, 42, Range.atLeast(0), Importance.High, &quot;Configuration with user provided validator.&quot;);
60:  * // check {@link #define(String, Type, Importance, String, String, int, Width, String, List) define(String, Type, Importance, String, String, int, Width, String, List&lt;String&gt;)} for more details.
61:  * defs.define(&quot;config_with_dependents&quot;, Type.INT, Importance.LOW, &quot;Configuration with dependents.&quot;, &quot;group&quot;, 1, Width.SHORT, &quot;Config With Dependents&quot;, Arrays.asList(&quot;config_with_default&quot;,&quot;config_with_validator&quot;));
62:  *
63:  * Map&lt;String, String&gt; props = new HashMap&lt;&gt;();
64:  * props.put(&quot;config_with_default&quot;, &quot;some value&quot;);
65:  * props.put(&quot;config_with_dependents&quot;, &quot;some other value&quot;);
66:  *
67:  * Map&lt;String, Object&gt; configs = defs.parse(props);
